#!/usr/bin/env bash
# apply-landing-trust.sh — cumulative superset installer (macOS + Linux safe).
# Supersedes apply-payment-hardening.sh / apply-legal-marketing.sh. Run ONLY this one.
set -euo pipefail
for D in "$HOME/freddy-fixit" "$HOME/Desktop/Website/freddy-fixit" "$HOME/Desktop/freddy-fixit"; do
  if [ -d "$D/.git" ]; then REPO="$D"; break; fi
done
if [ -z "${REPO:-}" ]; then echo "❌ Could not find the freddy-fixit repo. Edit REPO in this script."; exit 1; fi
echo "📂 Repo: $REPO"; cd "$REPO"
# decode reads base64 from stdin (works with both BSD/macOS and GNU base64)
decode() { mkdir -p "$(dirname "$1")"; base64 -d < "$2" > "$1"; echo "  ✓ $1"; }
TMP="$(mktemp -d)"
cat > "$TMP/f1.b64" <<'B64_1'

B64_1
decode "CLAUDE.md" "$TMP/f1.b64"
cat > "$TMP/f2.b64" <<'B64_2'

B64_2
decode "src/pages/ClientDashboard.tsx" "$TMP/f2.b64"
cat > "$TMP/f3.b64" <<'B64_3'

B64_3
decode "src/pages/Home.tsx" "$TMP/f3.b64"
cat > "$TMP/f4.b64" <<'B64_4'

B64_4
decode "src/pages/UserAgreement.tsx" "$TMP/f4.b64"
cat > "$TMP/f5.b64" <<'B64_5'

B64_5
decode "supabase/functions/create-payment-intent/index.ts" "$TMP/f5.b64"
cat > "$TMP/f6.b64" <<'B64_6'

B64_6
decode "supabase/functions/stripe-webhook/index.ts" "$TMP/f6.b64"

rm -rf "$TMP"
git add -A
git commit -m "Landing trust: hero trust bar, honest testimonials (no fabricated reviews), true stat; + payment hardening + legal/marketing copy" || { echo "Nothing to commit (already applied)."; exit 0; }
git push
echo "✅ pushed — hard-refresh (Cmd+Shift+R) ~1 min after Vercel deploys."
